@@ -845,6 +845,18 @@ static Instruction *foldNoWrapAdd(BinaryOperator &Add,
     return BinaryOperator::CreateAdd(WideX, NewC);
   }

+  // (zext nneg (X +nsw NarrowC)) + C --> (sext X) + (sext(NarrowC) + C)
+  if (match(Op0,
+            m_OneUse(m_ZExt(m_NSWAddLike(m_Value(X), m_Constant(NarrowC)))))) {
+    auto *ZExt = cast<PossiblyNonNegInst>(Op0);
+    if (ZExt->hasNonNeg()) {
+      Value *WideC = Builder.CreateSExt(NarrowC, Ty);
+      Value *NewC = Builder.CreateAdd(WideC, Op1C);
+      Value *WideX = Builder.CreateSExt(X, Ty);
+      return BinaryOperator::CreateAdd(WideX, NewC);
+    }
+  }
+
   return nullptr;
 }

@@ -930,6 +942,21 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
       C2->isMinSignedValue() && C2->sext(Ty->getScalarSizeInBits()) == *C)
     return CastInst::Create(Instruction::SExt, X, Ty);

+  // add(zext nneg (add nsw X, C1)), -C1 --> sext X
+  if (match(Op0, m_ZExt(m_Value(X)))) {
+    auto *ZExt = dyn_cast<PossiblyNonNegInst>(Op0);
+    if (ZExt && ZExt->hasNonNeg()) {
+      const APInt *C1;
+      Value *Y;
+      if (match(X, m_NSWAddLike(m_Value(Y), m_APInt(C1)))) {
+        // Compute C1 extended to the wide type with sign extension.
+        APInt C1Extended = C1->sext(Ty->getScalarSizeInBits());
+        if (C1Extended == -(*C))
+          return CastInst::Create(Instruction::SExt, Y, Ty);
+      }
+    }
+  }
